// === BBOX UNIÓN + ARRAY DE POLÍGONOS ===
const items = $input.all();

if (items.length === 0) {
  throw new Error('No hay polígonos activos. Verificar zonas_geograficas o array de zonas en query SQL.');
}

let minLat = Infinity, maxLat = -Infinity;
let minLon = Infinity, maxLon = -Infinity;
const polygons = [];

for (const item of items) {
  const data = item.json;
  minLat = Math.min(minLat, parseFloat(data.lat_sur));
  maxLat = Math.max(maxLat, parseFloat(data.lat_norte));
  minLon = Math.min(minLon, parseFloat(data.lon_oeste));
  maxLon = Math.max(maxLon, parseFloat(data.lon_este));

  const geo = JSON.parse(data.geom_geojson);
  polygons.push({
    nombre: data.nombre,
    coordinates: geo.coordinates[0]
  });
}

console.log(`BBox: lat ${minLat} → ${maxLat}, lon ${minLon} → ${maxLon}`);
console.log(`Polígonos: ${polygons.map(p => p.nombre).join(', ')}`);

return [{
  json: {
    bbox: { lat_sur: minLat, lat_norte: maxLat, lon_oeste: minLon, lon_este: maxLon },
    polygons,
    zonas_incluidas: items.map(i => i.json.nombre)
  }
}];

// === EXTRAER BIEN INMUEBLES (SIN FILTRO DE BARRIO) ===
// ZN v1.0.0: a diferencia del workflow Equipetrol, NO filtra por nomb_barri.
// Trae TODAS las props con lat/lon válidos; el filtro geográfico real
// lo hace el nodo "Filtrar por Polígonos" (point-in-polygon, fail-closed).
//
// La API devuelve un STRING JSON (no JSON parseado).
// n8n lo wrappea en {data: "[{...},{...}]"} → JSON.parse() sobre el string.

const raw = $input.first().json;
let allListings = [];

if (typeof raw.data === 'string') {
  allListings = JSON.parse(raw.data);
} else if (Array.isArray(raw.data)) {
  allListings = raw.data;
} else if (Array.isArray(raw)) {
  allListings = raw;
} else if (raw.id_cata) {
  allListings = [raw];
} else {
  const items = $input.all();
  if (items.length > 1) {
    allListings = items.map(i => i.json);
  } else {
    console.log('DEBUG - tipo:', typeof raw.data, 'keys:', Object.keys(raw).slice(0, 5));
    throw new Error('No se pudo parsear respuesta API. Tipo data: ' + typeof raw.data);
  }
}

console.log(`API devolvió ${allListings.length} listings total (sin filtro de barrio)`);

const BASE_URL = 'https://www.bieninmuebles.com.bo';

// Solo conservar props con lat/lon numéricos (el point-in-polygon los exige).
const conGps = allListings.filter(item => {
  const lat = item.latitud_cata && item.latitud_cata !== '' ? parseFloat(item.latitud_cata) : null;
  const lng = item.longitud_cata && item.longitud_cata !== '' ? parseFloat(item.longitud_cata) : null;
  return Number.isFinite(lat) && Number.isFinite(lng);
});

console.log(`Con GPS válido: ${conGps.length} de ${allListings.length}`);

const propiedades = conGps.map(item => {
  const precioRaw = String(item.precio_cata || '0').replace(/,/g, '');
  const precio = parseFloat(precioRaw) || null;
  const moneda = item.moneda_cata === '2' ? 'USD' : 'BOB';
  const lat = parseFloat(item.latitud_cata);
  const lng = parseFloat(item.longitud_cata);

  return {
    url: `${BASE_URL}/property.php?id=${item.id_cata}`,
    fuente: 'bien_inmuebles',
    codigo_propiedad: item.code_cata || String(item.id_cata),
    precio_mensual_bob: moneda === 'BOB' ? precio : null,
    precio_mensual_usd: moneda === 'USD' ? precio : null,
    moneda_original: moneda,
    area_total_m2: parseFloat(item.supterreno_cata) || null,
    dormitorios: parseInt(item.habitacion_cata) || null,
    banos: parseInt(item.banio_cata) || null,
    estacionamientos: null,
    tipo_propiedad_original: 'departamento',
    latitud: lat,
    longitud: lng,
    fecha_publicacion: null,
    metodo_discovery: 'zonanorte_bi_alquiler',
    zona: null,
    datos_json_discovery: item
  };
});

return [{
  json: {
    propiedades: propiedades,
    stats_fuente: {
      total_api: allListings.length,
      con_gps: conGps.length,
      fuente: 'bien_inmuebles'
    }
  }
}];

// === FILTRO POINT-IN-POLYGON (FUERA DEL LOOP) ===
// Filtra el array completo de propiedades emitido por "Extraer Propiedades".
function pointInPolygon(lon, lat, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > lat) !== (yj > lat)) &&
      (lon < (xj - xi) * (lat - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}

const polygons = $('Calcular BBox + Polígonos').first().json.polygons || [];
if (polygons.length === 0) {
  console.warn('Sin polígonos activos — devuelvo vacío (FAIL CLOSED)');
  return [{ json: { propiedades: [], stats: { total: 0, dentro: 0, fuera: 0 } } }];
}

const input = $input.first().json;
const propiedades = input.propiedades || [];

const dentro = propiedades.filter(p => {
  const lat = parseFloat(p.latitud);
  const lon = parseFloat(p.longitud);
  if (!Number.isFinite(lat) || !Number.isFinite(lon)) return false;
  return polygons.some(poly => pointInPolygon(lon, lat, poly.coordinates));
});

console.log(`Filtro polígono: ${dentro.length}/${propiedades.length} dentro de [${polygons.map(p => p.nombre).join(', ')}]`);

return [{
  json: {
    propiedades: dentro,
    stats: {
      total: propiedades.length,
      dentro: dentro.length,
      fuera: propiedades.length - dentro.length
    }
  }
}];

// === PREPARAR COMPARACIÓN ALQUILERES ===
// Lee las propiedades del nodo Filtrar (ya filtradas por polígono) y compara con BD.
const snapshot = $('Filtrar por Polígonos').first().json.propiedades || [];
const propiedadesBD = $('Obtener Alquileres Activos BD').all().map(item => item.json);

const snapshotDedup = new Map();
for (const prop of snapshot) {
  snapshotDedup.set(prop.url, prop);
}

const urlsSnapshot = new Set(snapshotDedup.keys());
const urlsBD = new Map(propiedadesBD.map(p => [p.url, { id: p.id, status: p.status }]));

const nuevas = [];
const existentes = [];
const ausentes = [];

for (const [url, prop] of snapshotDedup) {
  if (!urlsBD.has(url)) {
    nuevas.push(prop);
  } else {
    existentes.push({
      ...prop,
      _id_bd: urlsBD.get(url).id,
      _status_bd: urlsBD.get(url).status
    });
  }
}

for (const [url, info] of urlsBD) {
  if (!urlsSnapshot.has(url)) {
    if (!['inactivo_pending', 'inactivo_confirmed'].includes(info.status)) {
      ausentes.push({ id: info.id, url: url, status_actual: info.status });
    }
  }
}

return [{
  json: {
    nuevas,
    existentes,
    ausentes,
    stats: {
      total_snapshot: snapshotDedup.size,
      total_bd: urlsBD.size,
      nuevas: nuevas.length,
      existentes: existentes.length,
      ausentes: ausentes.length
    }
  }
}];

// === LOG STATS BIEN INMUEBLES ALQUILER ZONA NORTE ===
const stats = $input.first().json.stats;
const fuente = $('Extraer Propiedades').first().json.stats_fuente;
const poly = $('Filtrar por Polígonos').first().json.stats;

console.log(`
=== DISCOVERY BIEN INMUEBLES ALQUILER ZONA NORTE ===
API total: ${fuente.total_api}
Con GPS: ${fuente.con_gps}
Dentro de polígono ZN: ${poly.dentro}
---
BD activas (ZN): ${stats.total_bd}
Nuevas: ${stats.nuevas}
Existentes: ${stats.existentes}
Ausentes: ${stats.ausentes}
===================================================
`);

return $input.all();

// === PREPARAR PARA registrar_discovery_alquiler() ===
const data = $input.first().json;
const nuevas = data.nuevas || [];
const existentes = data.existentes || [];
const todas = [...nuevas, ...existentes];

if (todas.length === 0) {
  return [{ json: { skip: true, message: 'No hay alquileres para procesar' } }];
}

return todas.map(prop => ({
  json: {
    p_url: prop.url,
    p_fuente: prop.fuente,
    p_codigo_propiedad: String(prop.codigo_propiedad || ''),
    p_precio_mensual_bob: prop.precio_mensual_bob,
    p_precio_mensual_usd: prop.precio_mensual_usd,
    p_moneda_original: prop.moneda_original || 'BOB',
    p_area_total_m2: prop.area_total_m2,
    p_dormitorios: prop.dormitorios,
    p_banos: prop.banos,
    p_estacionamientos: prop.estacionamientos,
    p_tipo_propiedad_original: prop.tipo_propiedad_original,
    p_latitud: prop.latitud,
    p_longitud: prop.longitud,
    p_fecha_publicacion: prop.fecha_publicacion,
    p_metodo_discovery: prop.metodo_discovery,
    p_zona: prop.zona,
    p_datos_json_discovery: JSON.stringify(prop.datos_json_discovery)
  }
}));

// === PROCESAR AUSENTES ALQUILER ===
const ausentes = $input.first().json.ausentes;

if (ausentes.length === 0) {
  return [{ json: { skip: true, message: 'No hay alquileres ausentes' } }];
}

return ausentes.map(prop => ({
  json: {
    id: prop.id,
    url: prop.url,
    status_actual: prop.status_actual
  }
}));

// === RESUMEN FINAL BIEN INMUEBLES ALQUILER ZONA NORTE ===
const stats = $('Log Stats').first().json.stats;
const fuente = $('Extraer Propiedades').first().json.stats_fuente;
const poly = $('Filtrar por Polígonos').first().json.stats;
const zonas = $('Calcular BBox + Polígonos').first().json.zonas_incluidas;

const resumen = {
  timestamp: new Date().toISOString(),
  fuente: 'bien_inmuebles',
  workflow: 'Discovery Bien Inmuebles Alquiler Zona Norte',
  version: '1.0.0',
  zonas_activas: zonas,
  resultados: {
    api_total: fuente.total_api,
    con_gps: fuente.con_gps,
    dentro_poligono: poly.dentro,
    bd_activas: stats.total_bd,
    nuevas_insertadas: stats.nuevas,
    existentes_actualizadas: stats.existentes,
    ausentes_marcadas: stats.ausentes
  },
  status: 'completado'
};

console.log('=== DISCOVERY BIEN INMUEBLES ALQUILER ZONA NORTE COMPLETADO ===');
console.log(JSON.stringify(resumen, null, 2));

return [{ json: resumen }];
